// 模块2: 短暂视觉记忆 — 熊猫位置记忆
(function(){
var GOLD='#C9A84C',INITIAL_DIGITS=6,MAX_LIVES=3,GRID_SZ=4,CELL_SZ=90,GAP=8;
var sm=window.__shortmem={phase:'idle',digits:0,positions:[],order:[],userOrder:[],showTimer:0,displayPhase:'idle',lives:MAX_LIVES,digitCount:INITIAL_DIGITS,peakDigits:INITIAL_DIGITS,correct:0,wrong:0,trials:0,tutRound:0};

var pandaImg=null;(function(){var i=new Image();i.onload=function(){pandaImg=i;};i.src='data:image/jpeg;base64,';})();
var pandaWrongImg=null;(function(){var i2=new Image();i2.onload=function(){pandaWrongImg=i2;};i2.src='data:image/jpeg;base64,';})();

function playCoin(){try{var a=new(window.AudioContext||window.webkitAudioContext)(),t=a.currentTime,o=a.createOscillator(),g=a.createGain();o.connect(g);g.connect(a.destination);o.type='sine';o.frequency.setValueAtTime(1200,t);o.frequency.setValueAtTime(1600,t+.05);o.frequency.setValueAtTime(2000,t+.1);g.gain.setValueAtTime(.1,t);g.gain.setValueAtTime(.1,t+.1);g.gain.exponentialRampToValueAtTime(.01,t+.2);o.start(t);o.stop(t+.3);}catch(e){}}
function playError(){try{var a2=new(window.AudioContext||window.webkitAudioContext)(),t2=a2.currentTime,o2=a2.createOscillator(),g2=a2.createGain();o2.connect(g2);g2.connect(a2.destination);o2.type='square';o2.frequency.setValueAtTime(200,t2);o2.frequency.linearRampToValueAtTime(100,t2+.25);g2.gain.setValueAtTime(.15,t2);g2.gain.exponentialRampToValueAtTime(.001,t2+.3);o2.start(t2);o2.stop(t2+.3);}catch(e){}}
function drawRR(ctx,x,y,w,h,r){ctx.beginPath();ctx.moveTo(x+r,y);ctx.lineTo(x+w-r,y);ctx.arcTo(x+w,y,x+w,y+r,r);ctx.lineTo(x+w,y+h-r);ctx.arcTo(x+w,y+h,x+w-r,y+h,r);ctx.lineTo(x+r,y+h);ctx.arcTo(x,y+h,x,y+h-r,r);ctx.lineTo(x,y+r);ctx.arcTo(x,y,x+r,y,r);ctx.closePath();}
function genPos(n){var cells=[];for(var r=0;r<GRID_SZ;r++)for(var c=0;c<GRID_SZ;c++)cells.push({r:r,c:c});for(var i=cells.length-1;i>0;i--){var j=Math.floor(Math.random()*(i+1));var t=cells[i];cells[i]=cells[j];cells[j]=t;}return cells.slice(0,n);}
function gridOff(W,H){var gw=GRID_SZ*(CELL_SZ+GAP)-GAP;return{x:W/2-gw/2,y:H/2-gw/2-20};}
function cellXY(off,r,c){return{x:off.x+c*(CELL_SZ+GAP),y:off.y+r*(CELL_SZ+GAP)};}

function updateUI(){
    var st=document.getElementById('stroop-status'),sc=document.getElementById('stroop-score');
    if(st){if(sm.phase==='ready')st.textContent='短暂视觉记忆';else if(sm.phase==='tutorial_text')st.textContent='游戏规则';else if(sm.phase==='tutorial_1')st.textContent='教程1-手指引导';else if(sm.phase==='tutorial_2')st.textContent='教程2-记忆点击';else if(sm.phase==='ready_game')st.textContent='准备开始';else if(sm.phase==='playing')st.textContent='';else if(sm.phase==='done')st.textContent='';}
    if(sc)sc.textContent=sm.phase==='playing'?'正确:'+sm.correct+'/'+sm.trials:'';
}
sm.showReady=function(){sm.phase='ready';updateUI();};
sm.startTutorial=function(){sm.phase='tutorial_text';updateUI();};
function startTut1(){sm.phase='tutorial_1';sm.positions=genPos(3);sm.order=[1,2,3];sm.userOrder=[];sm.displayPhase='ready_countdown';sm.showTimer=performance.now();sm.tutRound=1;updateUI();}
function startTut2(){sm.phase='tutorial_2';sm.digits=4;sm.positions=genPos(4);sm.order=[];for(var i=1;i<=4;i++)sm.order.push(i);sm.userOrder=[];sm.displayPhase='ready_countdown';sm.showTimer=performance.now();sm._showIdx=0;sm._shownDone=false;sm._lastCorrect=null;sm._wrongCell=null;updateUI();}
sm.showReadyGame=function(){sm.phase='ready_game';updateUI();};
sm.showReadyStart=function(){sm.phase='ready_start';updateUI();};

function startPlaying(){sm.phase='playing';sm.trials=0;sm.correct=0;sm.wrong=0;sm.lives=MAX_LIVES;sm.digitCount=INITIAL_DIGITS;sm.peakDigits=INITIAL_DIGITS;startTrial();updateUI();}
function startTrial(){sm.digits=sm.digitCount;sm.positions=genPos(sm.digits);sm.order=[];for(var i=1;i<=sm.digits;i++)sm.order.push(i);sm.userOrder=[];sm.displayPhase='ready_countdown';sm.showTimer=performance.now();sm._showIdx=0;sm._shownDone=false;sm._lastCorrect=null;sm._wrongCell=null;}

function clickCell(r,c){
    if(sm.phase==='tutorial_1'&&sm.displayPhase==='finger'){
        var ti=sm.userOrder.length;if(ti>=3)return;var p=sm.positions[ti];if(r===p.r&&c===p.c){sm.userOrder.push(ti+1);playCoin();if(sm.userOrder.length>=3){sm.displayPhase='tut1_done';sm.showTimer=performance.now();}updateUI();}
    }else if(sm.phase==='tutorial_2'&&sm.displayPhase==='input'){handleGameClick(r,c);}
    else if(sm.phase==='playing'&&sm.displayPhase==='input'){handleGameClick(r,c);}
}
function handleGameClick(r,c){
    for(var i=0;i<sm.positions.length;i++){var p=sm.positions[i];if(r===p.r&&c===p.c){var num=i+1;if(num===sm.order[sm.userOrder.length]){sm.userOrder.push(num);playCoin();sm._lastCorrect=p;sm._lastCorrectT=performance.now();if(sm.userOrder.length>=sm.order.length){checkAnswer();}return;}else{break;}}}
    sm.userOrder=[];sm.trials++;sm.wrong++;playError();sm._wrongCell={r:r,c:c};sm._wrongT=performance.now();sm._lastCorrect=null;
    if(sm.phase==='tutorial_2'){sm.userOrder=[];sm._wrongCell={r:r,c:c};sm._wrongT=performance.now();setTimeout(function(){if(sm.phase==='tutorial_2'){sm.tutFeedbackOk=false;sm.tutFeedbackMsg='哦，不对';sm.phase='tutorial_feedback';sm._wrongCell=null;sm._wrongT=0;updateUI();}},700);updateUI();return;}
    else{sm.lives--;var done2=sm.lives<=0;if(done2){sm.digitCount=sm.peakDigits;setTimeout(function(){sm.phase='done';updateUI();},600);}setTimeout(function(){if(done2)return;sm.digitCount=Math.max(3,sm.digitCount-1);startTrial();updateUI();},700);}
}
function checkAnswer(){sm.trials++;sm.correct++;
    if(sm.phase==='tutorial_2'){sm.showReadyGame();return;}
    setTimeout(function(){sm.digitCount++;if(sm.digitCount>sm.peakDigits)sm.peakDigits=sm.digitCount;startTrial();updateUI();},1200);
}

function renderSmFB(ctx,W,H){
    ctx.fillStyle='#1a1a2e';ctx.fillRect(0,0,W,H);
    var msg=sm.tutFeedbackMsg||(sm.tutFeedbackOk?'对，再试一个':'哦，不对');
    var color=sm.tutFeedbackOk?'#4CAF50':'#F44336';
    var bw=440,bh=88,bx=W/2-bw/2,by=H/2-70;
    drawRR(ctx,bx,by,bw,bh,12);ctx.strokeStyle=GOLD;ctx.lineWidth=2;ctx.stroke();
    ctx.fillStyle=color;ctx.font='bold 28px sans-serif';ctx.textAlign='center';ctx.textBaseline='middle';
    ctx.fillText(msg,W/2,by+bh/2-15);
    ctx.textBaseline='alphabetic';ctx.textAlign='start';
    var btnW=140,btnH=44,btnX=W/2-btnW/2,btnY=by+bh+10;
    drawRR(ctx,btnX,btnY,btnW,btnH,12);ctx.fillStyle=GOLD;ctx.globalAlpha=.3;ctx.fill();ctx.globalAlpha=1;ctx.strokeStyle=GOLD;ctx.lineWidth=2;ctx.stroke();
    ctx.fillStyle=GOLD;ctx.font='bold 18px sans-serif';ctx.textAlign='center';ctx.textBaseline='middle';ctx.fillText('继续',btnX+btnW/2,btnY+btnH/2);ctx.textBaseline='alphabetic';ctx.textAlign='start';
    sm._fbBtn={x:btnX,y:btnY,w:btnW,h:btnH};
}

function renderShortMem(){
    var c=document.getElementById('cognitive-canvas');if(!c||c.style.display==='none'||!sm||sm.phase==='idle')return;
    if(window.__cogModule!=='shortmem')return;var ctx=c.getContext('2d'),W=c.width,H=c.height;
    ctx.fillStyle='#1a1a2e';ctx.fillRect(0,0,W,H);
    if(sm.phase==='ready')renderSMReady(ctx,W,H,false);else if(sm.phase==='ready_start')renderSMReady(ctx,W,H,true);
    else if(sm.phase==='tutorial_feedback')renderSmFB(ctx,W,H);
    else if(sm.phase==='tutorial_text')renderSMTutorial(ctx,W,H);else if(sm.phase==='ready_game')renderSMReadyGame(ctx,W,H);
    else if(sm.phase==='done')renderSMDone(ctx,W,H);else renderSMGame(ctx,W,H);
}

function renderSMReady(ctx,W,H,isStart){
    ctx.fillStyle='#fff';ctx.font='bold 36px sans-serif';ctx.textAlign='center';ctx.fillText('短暂视觉记忆',W/2,H/2-130);ctx.textAlign='start';
    var t1='考验你记住画面的能力',t2='分数越高，代表着你的记忆力越强';
    ctx.font='bold 18px sans-serif';var bw=440,bh=88,bx=W/2-bw/2,by=H/2-70;
    drawRR(ctx,bx,by,bw,bh,12);ctx.strokeStyle=GOLD;ctx.lineWidth=2;ctx.stroke();
    ctx.fillStyle='#fff';ctx.textAlign='center';ctx.textBaseline='middle';ctx.fillText(t1,W/2,by+40);ctx.fillText(t2,W/2,by+68);ctx.textBaseline='alphabetic';ctx.textAlign='start';
    var bw2=160,bh2=48,bx2=W/2-bw2/2,by2=by+bh+10;
    drawRR(ctx,bx2,by2,bw2,bh2,12);ctx.fillStyle=GOLD;ctx.globalAlpha=.3;ctx.fill();ctx.globalAlpha=1;ctx.strokeStyle=GOLD;ctx.lineWidth=2;ctx.stroke();
    ctx.fillStyle=GOLD;ctx.font='bold 20px sans-serif';ctx.textAlign='center';ctx.textBaseline='middle';ctx.fillText(isStart?'开始':(sm.phase==='ready_start'?'开始':'开始教程'),W/2,by2+bh2/2);ctx.textBaseline='alphabetic';ctx.textAlign='start';
    sm._rb={x:bx2,y:by2,w:bw2,h:bh2};
}
function renderSMTutorial(ctx,W,H){
    var t='依次点击出现过的小动物';ctx.font='bold 18px sans-serif';var bw=440,bh=76,bx=W/2-bw/2,by=H/2-65;
    drawRR(ctx,bx,by,bw,bh,12);ctx.strokeStyle=GOLD;ctx.lineWidth=2;ctx.stroke();
    ctx.fillStyle='#fff';ctx.textAlign='center';ctx.textBaseline='middle';ctx.fillText(t,W/2,by+50);ctx.textBaseline='alphabetic';ctx.textAlign='start';
    var bw2=140,bh2=44,bx2=W/2-bw2/2,by2=by+bh+10;drawRR(ctx,bx2,by2,bw2,bh2,12);ctx.fillStyle=GOLD;ctx.globalAlpha=.3;ctx.fill();ctx.globalAlpha=1;ctx.strokeStyle=GOLD;ctx.lineWidth=2;ctx.stroke();
    ctx.fillStyle=GOLD;ctx.font='bold 18px sans-serif';ctx.textAlign='center';ctx.textBaseline='middle';ctx.fillText('继续',W/2,by2+bh2/2);ctx.textBaseline='alphabetic';ctx.textAlign='start';sm._tb={x:bx2,y:by2,w:bw2,h:bh2};
}
function renderSMReadyGame(ctx,W,H){
    var t='对就是这样，现在正式开始游戏吧';ctx.font='bold 22px sans-serif';var tw=ctx.measureText(t).width;var bw=tw+120,bh=76,bx=W/2-bw/2,by=H/2-65;
    drawRR(ctx,bx,by,bw,bh,12);ctx.strokeStyle=GOLD;ctx.lineWidth=2;ctx.stroke();ctx.fillStyle='#fff';ctx.textAlign='center';ctx.textBaseline='middle';ctx.fillText(t,W/2,by+50);ctx.textBaseline='alphabetic';ctx.textAlign='start';
    var bw2=160,bh2=44,bx2=W/2-bw2/2,by2=by+bh+10;drawRR(ctx,bx2,by2,bw2,bh2,12);ctx.fillStyle=GOLD;ctx.globalAlpha=.3;ctx.fill();ctx.globalAlpha=1;ctx.strokeStyle=GOLD;ctx.lineWidth=2;ctx.stroke();
    ctx.fillStyle=GOLD;ctx.font='bold 18px sans-serif';ctx.textAlign='center';ctx.textBaseline='middle';ctx.fillText('开始游戏',W/2,by2+bh2/2);ctx.textBaseline='alphabetic';ctx.textAlign='start';sm._rgb={x:bx2,y:by2,w:bw2,h:bh2};
}
function renderSMTut1Done(ctx,W,H){
    var t='对就是这样，下面开始下一关';ctx.font='bold 22px sans-serif';var bw=500,bh=76,bx=W/2-bw/2,by=H/2-65;
    drawRR(ctx,bx,by,bw,bh,12);ctx.strokeStyle=GOLD;ctx.lineWidth=2;ctx.stroke();ctx.fillStyle='#fff';ctx.textAlign='center';ctx.textBaseline='middle';ctx.fillText(t,W/2,by+50);ctx.textBaseline='alphabetic';ctx.textAlign='start';
    var bw2=140,bh2=44,bx2=W/2-bw2/2,by2=by+bh+10;drawRR(ctx,bx2,by2,bw2,bh2,12);ctx.fillStyle=GOLD;ctx.globalAlpha=.3;ctx.fill();ctx.globalAlpha=1;ctx.strokeStyle=GOLD;ctx.lineWidth=2;ctx.stroke();
    ctx.fillStyle=GOLD;ctx.font='bold 18px sans-serif';ctx.textAlign='center';ctx.textBaseline='middle';ctx.fillText('继续',W/2,by2+bh2/2);ctx.textBaseline='alphabetic';ctx.textAlign='start';sm._tut1ContBtn={x:bx2,y:by2,w:bw2,h:bh2};
}
function renderSMDone(ctx,W,H){
    ctx.fillStyle='#fff';ctx.font='bold 36px sans-serif';ctx.textAlign='center';ctx.fillText('短暂视觉记忆',W/2,H/2-130);ctx.textAlign='start';
    ctx.font='bold 22px sans-serif';ctx.fillStyle='#aaa';ctx.textAlign='center';ctx.fillText('当前测试结束',W/2,H/2-70);ctx.textAlign='start';
    var bw2=160,bh2=48,by2=H/2,bx1=W/2-bw2-20,bx2=W/2+20;
    drawRR(ctx,bx1,by2,bw2,bh2,12);ctx.fillStyle=GOLD;ctx.globalAlpha=.3;ctx.fill();ctx.globalAlpha=1;ctx.strokeStyle=GOLD;ctx.lineWidth=2;ctx.stroke();
    ctx.fillStyle=GOLD;ctx.font='bold 18px sans-serif';ctx.textAlign='center';ctx.textBaseline='middle';ctx.fillText('重新开始',bx1+bw2/2,by2+bh2/2);ctx.textBaseline='alphabetic';ctx.textAlign='start';
    drawRR(ctx,bx2,by2,bw2,bh2,12);ctx.fillStyle=GOLD;ctx.globalAlpha=.3;ctx.fill();ctx.globalAlpha=1;ctx.strokeStyle=GOLD;ctx.lineWidth=2;ctx.stroke();
    ctx.fillStyle=GOLD;ctx.font='bold 18px sans-serif';ctx.textAlign='center';ctx.textBaseline='middle';ctx.fillText('下一项测试',bx2+bw2/2,by2+bh2/2);ctx.textBaseline='alphabetic';ctx.textAlign='start';
    sm._db1={x:bx1,y:by2,w:bw2,h:bh2};sm._db2={x:bx2,y:by2,w:bw2,h:bh2};
}

function renderSMGame(ctx,W,H){
    var n2=performance.now(),off=gridOff(W,H);
    // 新回合提示 (显示在框中间, 2秒后消失)
    if(sm.displayPhase==='ready_countdown'){if(n2-sm.showTimer>2000){sm.displayPhase='showing';sm.showTimer=n2;sm._showIdx=0;sm._shownDone=false;}}
    // 教程1展示完后进入手指阶段
    if(sm.phase==='tutorial_1'&&sm.displayPhase==='showing'){var el2=n2-sm.showTimer;sm._showIdx=Math.floor(el2/1000);if(sm._showIdx>=sm.positions.length){sm.displayPhase='finger';sm.userOrder=[];}}
    // tutorial 1 完成画面
    if(sm.phase==='tutorial_1'&&sm.displayPhase==='tut1_done'){renderSMTut1Done(ctx,W,H);return;}
    // tutorial 2 完成 → ready_game
    if(sm.phase==='tutorial_2'&&sm.displayPhase==='tut2_done'){if(n2-sm.showTimer>1500){sm.showReadyGame();}renderSMReadyGame(ctx,W,H);return;}

    // 爱心
    if(sm.phase==='playing'){ctx.font='bold 14px sans-serif';ctx.fillStyle='#aaa';ctx.textAlign='center';ctx.fillText('剩余尝试次数',W/2,off.y-55);ctx.textAlign='start';var h='';for(var li=0;li<MAX_LIVES;li++)h+=li<sm.lives?'❤️':'🖤';ctx.font='bold 22px sans-serif';ctx.fillStyle='#fff';ctx.textAlign='center';ctx.fillText(h,W/2,off.y-30);ctx.textAlign='start';
        ctx.fillStyle='#888';ctx.font='14px sans-serif';ctx.textAlign='center';ctx.fillText(sm.correct+'/'+sm.trials,W/2,25);ctx.textAlign='start';}
    // 标题
    if(sm.phase==='tutorial_1'&&sm.displayPhase==='finger'){ctx.font='bold 22px sans-serif';ctx.fillStyle='#FF9800';ctx.textAlign='center';ctx.fillText('按顺序点击熊猫',W/2,off.y-30);ctx.textAlign='start';}
    if(sm.phase==='tutorial_2'||sm.phase==='playing'){ctx.font='bold 20px sans-serif';ctx.fillStyle='#fff';ctx.textAlign='center';ctx.fillText(sm.displayPhase==='showing'?'记住出现的顺序...':'大熊猫出现的顺序是？',W/2,sm.phase==='playing'?off.y-80:off.y-30);ctx.textAlign='start';}

    // 4*4网格 (淡蓝色背景)
    for(var r=0;r<GRID_SZ;r++){for(var c2=0;c2<GRID_SZ;c2++){var cp=cellXY(off,r,c2);drawRR(ctx,cp.x,cp.y,CELL_SZ,CELL_SZ,12);ctx.fillStyle='rgba(144,202,249,0.3)';ctx.fill();ctx.strokeStyle='rgba(255,255,255,0.3)';ctx.lineWidth=2;ctx.stroke();}}

    // 熊猫显示逻辑
    var tut1Show=(sm.phase==='tutorial_1'&&(sm.displayPhase==='showing'||sm.displayPhase==='finger')); // 教程1显示不隐藏
    var showSeq=(sm.displayPhase==='showing'&&sm.phase!=='tutorial_1');
    var nowIdx=-1;
    if(showSeq){var el=n2-sm.showTimer;nowIdx=Math.floor(el/1000);}
    // 播放完成→进入input
    if(showSeq&&nowIdx>=sm.positions.length&&!sm._shownDone){sm._shownDone=true;if(sm.phase==='tutorial_2'||sm.phase==='playing')sm.displayPhase='input';}

    for(var i=0;i<sm.positions.length;i++){
        var pos=sm.positions[i],cp2=cellXY(off,pos.r,pos.c);
        var visible=false;
        // 展示阶段: 只显示当前一个熊猫(key difference from before)
        if(sm.phase==='tutorial_1'&&sm.displayPhase==='showing')visible=(i===sm._showIdx&&sm._showIdx<sm.positions.length);
        else if(sm.phase==='tutorial_1'&&sm.displayPhase==='finger')visible=true; // 教程1手指阶段全部显示
        else if(showSeq)visible=(i===nowIdx&&nowIdx<sm.positions.length); // 正式/tutorial2 每次只显示一个
        // 正确点击后闪一下
        if(sm._lastCorrect&&sm._lastCorrect.r===pos.r&&sm._lastCorrect.c===pos.c&&n2-sm._lastCorrectT<800)visible=true;
        if(visible&&pandaImg){var pad=10;drawRR(ctx,cp2.x+pad,cp2.y+pad,CELL_SZ-pad*2,CELL_SZ-pad*2,10);ctx.fillStyle='rgba(255,255,255,0.95)';ctx.fill();ctx.drawImage(pandaImg,cp2.x+pad+2,cp2.y+pad+2,CELL_SZ-(pad+2)*2,CELL_SZ-(pad+2)*2);
            ctx.fillStyle='#FF9800';ctx.font='bold 28px sans-serif';ctx.textAlign='right';if(sm.phase==='tutorial_1')ctx.fillText(i+1,cp2.x+CELL_SZ-8,cp2.y+20);ctx.textAlign='start';}
        // 手指
        if(sm.phase==='tutorial_1'&&sm.displayPhase==='finger'){var ti=sm.userOrder.length;if(ti<3){var tp=sm.positions[ti];if(pos.r===tp.r&&pos.c===tp.c){ctx.font='bold 40px sans-serif';ctx.fillStyle='#FF9800';ctx.textAlign='right';ctx.fillText('☝',cp2.x+CELL_SZ+10,cp2.y+CELL_SZ-10);ctx.textAlign='start';}}}
    }
    // 错误红块 (独立渲染任意格子)
    if(sm._wrongCell&&n2-sm._wrongT<700){var wcp=cellXY(off,sm._wrongCell.r,sm._wrongCell.c);if(pandaWrongImg.complete&&pandaWrongImg.naturalWidth>0){ctx.drawImage(pandaWrongImg,wcp.x+6,wcp.y+6,CELL_SZ-12,CELL_SZ-12);}ctx.strokeStyle='#d32f2f';ctx.lineWidth=5;drawRR(ctx,wcp.x+2,wcp.y+2,CELL_SZ-4,CELL_SZ-4,12);ctx.stroke();}
    // "新的回合" 覆盖提示
    if(sm.displayPhase==='ready_countdown'){var animDur=700,el3=n2-sm.showTimer,t3=Math.min(1,el3/animDur),c1=1.70158,c3v=c1+1,e3=1+c3v*Math.pow(t3-1,3)+c1*Math.pow(t3-1,2);ctx.save();ctx.translate(W/2,H/2);ctx.rotate(-180*(1-e3)*Math.PI/180);ctx.scale(e3,e3);ctx.globalAlpha=e3;ctx.font='bold 36px sans-serif';ctx.fillStyle='rgba(255,255,255,0.95)';ctx.textAlign='center';ctx.textBaseline='middle';ctx.fillText('新的回合',0,0);ctx.restore();}
    // 下方提示
    if(sm.displayPhase==='input'){ctx.font='bold 16px sans-serif';ctx.fillStyle='#aaa';ctx.textAlign='center';ctx.fillText('请按顺序点击出现过熊猫的方格',W/2,off.y+GRID_SZ*(CELL_SZ+GAP)+20);ctx.textAlign='start';}
    if(sm.phase==='tutorial_1'&&sm.displayPhase==='finger'){ctx.font='bold 16px sans-serif';ctx.fillStyle='#aaa';ctx.textAlign='center';ctx.fillText('大熊猫出现的顺序是？',W/2,off.y+GRID_SZ*(CELL_SZ+GAP)+20);ctx.textAlign='start';}
}

function handleClick(ex,ey){
    var c2=document.getElementById('cognitive-canvas');if(!c2||c2.style.display==='none')return false;
    if(window.__cogModule!=='shortmem')return false;var rect=c2.getBoundingClientRect();if(!rect)return false;
    var mx=(ex-rect.left)*(c2.width/rect.width),my=(ey-rect.top)*(c2.height/rect.height),W=c2.width,H=c2.height;
    // screen buttons
    if((sm.phase==='ready'||sm.phase==='ready_start')&&sm._rb){var rb=sm._rb;if(mx>=rb.x&&mx<=rb.x+rb.w&&my>=rb.y&&my<=rb.y+rb.h){if(sm.phase==='ready_start'){startPlaying();}else{sm.startTutorial();}return true;}return false;}
    if(sm.phase==='tutorial_text'&&sm._tb){var tb=sm._tb;if(mx>=tb.x&&mx<=tb.x+tb.w&&my>=tb.y&&my<=tb.y+tb.h){startTut1();return true;}return false;}
    // tutorial1 done button
    if(sm.phase==='tutorial_1'&&sm.displayPhase==='tut1_done'&&sm._tut1ContBtn){var tcb=sm._tut1ContBtn;if(mx>=tcb.x&&mx<=tcb.x+tcb.w&&my>=tcb.y&&my<=tcb.y+tcb.h){startTut2();return true;}return false;}
    if(sm.phase==='tutorial_feedback'&&sm._fbBtn){var fb=sm._fbBtn;if(mx>=fb.x&&mx<=fb.x+fb.w&&my>=fb.y&&my<=fb.y+fb.h){if(sm.tutFeedbackOk){sm.showReadyGame();}else{startTut2();}return true;}return false;}
    if(sm.phase==='ready_game'&&sm._rgb){var rgb=sm._rgb;if(mx>=rgb.x&&mx<=rgb.x+rgb.w&&my>=rgb.y&&my<=rgb.y+rgb.h){sm.showReadyStart();return true;}return false;}
    if(sm.phase==='done'){if(sm._db1&&mx>=sm._db1.x&&mx<=sm._db1.x+sm._db1.w&&my>=sm._db1.y&&my<=sm._db1.y+sm._db1.h){sm.showReadyStart();return true;}if(sm._db2&&mx>=sm._db2.x&&mx<=sm._db2.x+sm._db2.w&&my>=sm._db2.y&&my<=sm._db2.y+sm._db2.h){window._nextModule("shortmem");return true;}return false;}
    // grid
    if(sm.phase==='tutorial_1'||sm.phase==='tutorial_2'||sm.phase==='playing'){var off=gridOff(W,H);for(var r=0;r<GRID_SZ;r++){for(var c3=0;c3<GRID_SZ;c3++){var cp=cellXY(off,r,c3);if(mx>=cp.x&&mx<=cp.x+CELL_SZ&&my>=cp.y&&my<=cp.y+CELL_SZ){clickCell(r,c3);return true;}}}}
    return false;
}

setTimeout(function(){
    document.querySelectorAll('.cog-mod-btn').forEach(function(btn){if(btn.dataset.mod==='shortmem'){btn.addEventListener('click',function(){document.querySelectorAll('.cog-mod-btn').forEach(function(b){b.classList.remove('active');b.style.background='transparent';b.style.color='var(--text)';});btn.classList.add('active');btn.style.background='var(--primary)';btn.style.color='var(--bg-dark)';window.__cogModule='shortmem';document.getElementById('cog-panel-planning').style.display='none';document.getElementById('cog-panel-inhibition').style.display='block';sm.showReady();});}});
},600);
(function loop(){renderShortMem();requestAnimationFrame(loop);})();
(function(){var prev=window._handleCogClick;window._handleCogClick=function(ex,ey){if(window.__cogModule==='shortmem'&&handleClick(ex,ey))return true;if(prev)return prev(ex,ey);return false;};})();
})();
